 46	int get_field(database_event_format *f, char *field, char *type)
 47	{
 48	  int i;
 49	  for (i = 0; i < f->count; i++)
 50	    if (!strcmp(f->name[i], field)) {
 51	      if (strcmp(f->type[i], type)) break;
 52	      return i;
 53	    }
 54	  printf("bad field %s, check that it exists and has type '%s'\n",field,type);
 55	  exit(1);
 56	}
 57	
 58	void process_cache(FILE *out, cache_t *c, int n, int frame, int subframe)
 59	{
 60	  int i;
 61	  struct tm *t;
 62	
 63	  for (i = 0; i < n; i++)
 64	    if (c[i].filled == 0 || c[i].error == 1)
 65	      goto error;
 66	
 67	  for (i = 0; i < n; i++)
 68	    fwrite(c[i].b.obuf, c[i].b.osize, 1, out);
 69	
 70	  clear_cache(n, c);
 71	  return;
 72	
 73	error:
 74	  printf("ERROR: incorrect data at frame %d subframe %d", frame, subframe);
 75	  for (i = 0; i < n; i++) if (c[i].filled) {
 76	    t = localtime(&c[i].t.tv_sec);
 77	    printf(" [tag %d time %2.2d:%2.2d:%2.2d.%9.9ld]", i,
 78	           t->tm_hour, t->tm_min, t->tm_sec, c[i].t.tv_nsec);
 79	  }
 80	  printf("\n");
 81	  clear_cache(n, c);
 82	}
